import React from 'react'
import styled from 'styled-components'
import BannerGif from './static/Banner.gif'


const BlendBackground = styled.div `
background-color:rgba(0, 0, 0, 0.3);
width:100vw;
height:500px;
position:absolute;
`

const BannerGIF = styled.div `
background-image:url(${BannerGif});
width:100vw;
height:500px;
background-size:cover;
background-position:center;
background-repeat:no-repeat;
display:flex;
flex-direction:column;
justify-content:center;
align-items:center;
`
const Title = styled.div `
font-size:2.2rem;
color:white;
font-weight:bold;
z-index:1;
`

const Content = styled.p `
font-size:1.8rem;
color:white;
`

const ButtonWrapper = styled.div ``

const MensWear = styled.button `
border:1px solid white;
padding:10px 15px;
width:18vw;
height:10vh;
background-color:transparent;
border-radius:4px;
font-size:1.2rem;
color:white;
`

const WomensWear = styled.button `
border:1px solid white;
padding:10px 15px;
width:18vw;
margin-left:40px;
height:10vh;
background-color:transparent;
border-radius:4px;
font-size:1.2rem;
color:white;
`

export default function Banner () {
	return (
		<>
		<BannerGIF>
			<Title>Ultimate Platform for Your Designer Clothing</Title>
			<Content>Sell today</Content>
			<ButtonWrapper>
				<MensWear>Shop MENSWEAR</MensWear>
				<WomensWear>Shop WOMENSWEAR</WomensWear>
			</ButtonWrapper>
			<BlendBackground />
		</BannerGIF>
		</>
	)
}
